REFRESH MATERIALIZED VIEW atlas.mv_india_pulse;
REFRESH MATERIALIZED VIEW atlas.mv_sector_cards;
REFRESH MATERIALIZED VIEW atlas.mv_sector_deepdive;
REFRESH MATERIALIZED VIEW atlas.mv_sector_rrg;
REFRESH MATERIALIZED VIEW atlas.mv_sector_rotation_state;

-- which MVs reference predicted_excess / cell_predicted_excess
SELECT matviewname FROM pg_matviews WHERE schemaname='atlas' AND (definition ILIKE '%predicted_excess%')
ORDER BY matviewname;

SELECT matviewname FROM pg_matviews
WHERE schemaname='atlas' AND (matviewname ILIKE '%conviction%' OR matviewname ILIKE '%landscape%' OR matviewname ILIKE '%trader%' OR matviewname ILIKE '%landing%')
ORDER BY matviewname;

-- columns of atlas_fund_decisions_daily
SELECT column_name, data_type FROM information_schema.columns
WHERE table_schema='atlas' AND table_name='atlas_fund_decisions_daily' ORDER BY ordinal_position;

-- columns of atlas_stock_conviction_daily
SELECT column_name, data_type FROM information_schema.columns
WHERE table_schema='atlas' AND table_name='atlas_stock_conviction_daily' ORDER BY ordinal_position;

-- H5: is there a prior-state column to detect transitions? Check mv_fund_deepdive columns for stage/transition
SELECT column_name, data_type FROM information_schema.columns
WHERE table_schema='atlas' AND table_name='mv_fund_deepdive' ORDER BY ordinal_position;

-- atlas_fund_signal_unified: does it carry recommendation + state + stage pcts? distribution at latest
SELECT 'sig_unified_cols' k, string_agg(column_name, ', ' ORDER BY ordinal_position) v
FROM information_schema.columns WHERE table_schema='atlas' AND table_name='atlas_fund_signal_unified';

WITH r AS (
  SELECT * FROM atlas.mv_india_pulse WHERE as_of_date = (SELECT max(as_of_date) FROM atlas.mv_india_pulse)
)
SELECT 'breadth_table' AS section, jsonb_pretty(breadth_table) AS j FROM r;

WITH r AS (
  SELECT * FROM atlas.mv_india_pulse WHERE as_of_date = (SELECT max(as_of_date) FROM atlas.mv_india_pulse)
)
SELECT jsonb_pretty(headline_indices) FROM r;

WITH r AS (
  SELECT * FROM atlas.mv_india_pulse WHERE as_of_date = (SELECT max(as_of_date) FROM atlas.mv_india_pulse)
)
SELECT jsonb_pretty(tier_leadership) AS tier, jsonb_pretty(narrative_ribbon) AS ribbon, jsonb_pretty(dispersion_60d_series) AS disp FROM r;

SELECT DISTINCT benchmark_code
FROM atlas.atlas_benchmark_returns_cache
ORDER BY benchmark_code;
